from dataclasses import dataclass
from enum import Enum
import re


class ChangeType(Enum):
    BREAKING = "breaking"
    NON_BREAKING = "non_breaking"
    PATCH = "patch"   # documentation, description, comment only


@dataclass
class SchemaVersion:
    major: int
    minor: int
    patch: int = 0

    @classmethod
    def parse(cls, version_str: str) -> "SchemaVersion":
        """Parse 'v2.1' or '2.1.0' into a SchemaVersion."""
        cleaned = version_str.lstrip("v")
        parts = cleaned.split(".")
        major = int(parts[0])
        minor = int(parts[1]) if len(parts) > 1 else 0
        patch = int(parts[2]) if len(parts) > 2 else 0
        return cls(major, minor, patch)

    def bump(self, change_type: ChangeType) -> "SchemaVersion":
        if change_type == ChangeType.BREAKING:
            return SchemaVersion(self.major + 1, 0, 0)
        elif change_type == ChangeType.NON_BREAKING:
            return SchemaVersion(self.major, self.minor + 1, 0)
        else:
            return SchemaVersion(self.major, self.minor, self.patch + 1)

    def is_compatible_with(self, minimum: "SchemaVersion") -> bool:
        """True if this version satisfies >= minimum within the same major."""
        if self.major != minimum.major:
            return False
        if self.minor > minimum.minor:
            return True
        if self.minor == minimum.minor:
            return self.patch >= minimum.patch
        return False

    def __str__(self) -> str:
        return f"v{self.major}.{self.minor}.{self.patch}"


# Example: determine the correct version bump for a proposed change
def classify_metric_change(
    old_required_tags: set[str],
    new_required_tags: set[str],
    old_metric_type: str,
    new_metric_type: str,
    old_metric_name: str,
    new_metric_name: str,
) -> ChangeType:
    if old_metric_name != new_metric_name:
        return ChangeType.BREAKING
    if old_metric_type != new_metric_type:
        return ChangeType.BREAKING
    removed_tags = old_required_tags - new_required_tags
    if removed_tags:
        return ChangeType.BREAKING
    added_tags = new_required_tags - old_required_tags
    if added_tags:
        return ChangeType.BREAKING   # adding required tags breaks old emitters
    return ChangeType.NON_BREAKING

from dataclasses import dataclass
from typing import Any
import yaml


@dataclass
class SchemaDriftReport:
    metric_name: str
    undeclared_tags: list[str]    # tags emitted but not in schema
    missing_required_tags: list[str]   # required tags absent from emission
    invalid_tag_values: dict[str, str]  # tag → invalid value

    @property
    def has_drift(self) -> bool:
        return bool(self.undeclared_tags or self.missing_required_tags
                    or self.invalid_tag_values)

    def summary(self) -> str:
        if not self.has_drift:
            return f"{self.metric_name}: OK"
        parts = []
        if self.undeclared_tags:
            parts.append(f"undeclared tags: {self.undeclared_tags}")
        if self.missing_required_tags:
            parts.append(f"missing required: {self.missing_required_tags}")
        if self.invalid_tag_values:
            parts.append(f"invalid values: {self.invalid_tag_values}")
        return f"{self.metric_name}: DRIFT — " + "; ".join(parts)


def detect_schema_drift(
    schema_path: str,
    live_sample: dict[str, dict[str, Any]],  # metric_name → {tag: value, ...}
) -> list[SchemaDriftReport]:
    with open(schema_path) as f:
        schema = yaml.safe_load(f)

    metric_defs = {m["name"]: m for m in schema.get("metrics", [])}
    reports = []

    for metric_name, observed_tags in live_sample.items():
        defn = metric_defs.get(metric_name)
        if defn is None:
            reports.append(SchemaDriftReport(
                metric_name=metric_name,
                undeclared_tags=[],
                missing_required_tags=[],
                invalid_tag_values={"metric": "not declared in schema"},
            ))
            continue

        required = {t["name"] for t in defn["tags"].get("required", [])}
        optional = {t["name"] for t in defn["tags"].get("optional", [])}
        declared = required | optional

        undeclared = [k for k in observed_tags if k not in declared]
        missing_req = [k for k in required if k not in observed_tags]

        invalid_values: dict[str, str] = {}
        for tag_def in defn["tags"].get("required", []) + defn["tags"].get("optional", []):
            allowed = tag_def.get("values")
            if allowed and tag_def["name"] in observed_tags:
                val = observed_tags[tag_def["name"]]
                if val not in allowed:
                    invalid_values[tag_def["name"]] = val

        reports.append(SchemaDriftReport(
            metric_name=metric_name,
            undeclared_tags=undeclared,
            missing_required_tags=missing_req,
            invalid_tag_values=invalid_values,
        ))

    return reports

from dataclasses import dataclass, field
from typing import Optional
from datetime import date


@dataclass
class SchemaRegistration:
    service_name: str
    schema_version: str        # e.g. "v2.1"
    registered_at: str         # ISO date
    schema_url: str            # git permalink to the schema YAML
    contact: str               # team email or Slack channel


@dataclass
class DeprecationNotice:
    metric_name: str
    deprecated_in_version: str
    replacement: Optional[str]
    sunset_date: str           # ISO date — after this, metric stops being emitted
    migration_guide_url: str


class SchemaRegistry:
    def __init__(self) -> None:
        self._registrations: dict[str, SchemaRegistration] = {}
        self._deprecations: list[DeprecationNotice] = []

    def register(self, reg: SchemaRegistration) -> None:
        self._registrations[reg.service_name] = reg

    def deprecate(self, notice: DeprecationNotice) -> None:
        self._deprecations.append(notice)

    def services_on_deprecated_schema(
        self, deprecated_version: str
    ) -> list[str]:
        """Return service names still using a deprecated schema version."""
        return [
            name for name, reg in self._registrations.items()
            if reg.schema_version == deprecated_version
        ]

    def active_deprecations(self) -> list[DeprecationNotice]:
        today = date.today().isoformat()
        return [d for d in self._deprecations if d.sunset_date >= today]

    def overdue_migrations(self) -> list[tuple[str, DeprecationNotice]]:
        """Services that are past sunset date and still on deprecated metric."""
        today = date.today().isoformat()
        result = []
        for notice in self._deprecations:
            if notice.sunset_date < today:
                for service, reg in self._registrations.items():
                    # Simplified: check if service schema version predates fix
                    result.append((service, notice))
        return result
